package org.apache.commons.math.linear;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.linear.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.linear.steps;

import org.apache.commons.math.linear.EigenDecompositionImpl;
import org.apache.commons.math.linear.RealMatrix;
import org.apache.commons.math.linear.Array2DRowRealMatrix;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import io.cucumber.datatable.DataTable;
import java.util.List;
import java.util.ArrayList;
import static org.junit.Assert.*;

public class StepDefs {

    private double[] mainDiagonal;
    private double[] secondaryDiagonal;
    private double[] expectedEigenvalues;
    private Exception exception;
    private double[][] matrix;

    @Given("a symmetric tridiagonal matrix with main diagonal:")
    public void given_a_symmetric_tridiagonal_matrix_with_main_diagonal(DataTable dataTable) {
        List<List<String>> rows = dataTable.asLists();
        mainDiagonal = new double[rows.size()];
        for (int i = 0; i < rows.size(); i++) {
            mainDiagonal[i] = Double.parseDouble(rows.get(i).get(0));
        }
    }

    @Given("secondary diagonal:")
    public void given_secondary_diagonal(DataTable dataTable) {
        List<List<String>> rows = dataTable.asLists();
        secondaryDiagonal = new double[rows.size()];
        for (int i = 0; i < rows.size(); i++) {
            secondaryDiagonal[i] = Double.parseDouble(rows.get(i).get(0));
        }
    }

    @When("the eigen decomposition is computed")
    public void when_the_eigen_decomposition_is_computed() {
        try {
            // Use the tridiagonal constructor with main and secondary diagonals
            EigenDecompositionImpl decomposition = new EigenDecompositionImpl(mainDiagonal, secondaryDiagonal, 1e-12);
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the process should complete without throwing an exception")
    public void then_the_process_should_complete_without_throwing_an_exception() {
        if (exception != null) {
            fail("Exception was thrown: " + exception.getMessage());
        }
    }

    @Then("the real eigenvalues should be approximately:")
    public void then_the_real_eigenvalues_should_be_approximately(DataTable dataTable) {
        if (exception != null) {
            fail("Cannot verify eigenvalues when exception was thrown: " + exception.getMessage());
        }

        List<List<String>> rows = dataTable.asLists();
        expectedEigenvalues = new double[rows.size()];
        for (int i = 0; i < rows.size(); i++) {
            expectedEigenvalues[i] = Double.parseDouble(rows.get(i).get(0));
        }

        // Use the tridiagonal constructor with main and secondary diagonals
        EigenDecompositionImpl decomposition = new EigenDecompositionImpl(mainDiagonal, secondaryDiagonal, 1e-12);
        double[] actualEigenvalues = decomposition.getRealEigenvalues();

        // Sort both arrays for comparison
        java.util.Arrays.sort(actualEigenvalues);
        java.util.Arrays.sort(expectedEigenvalues);

        assertEquals("Number of eigenvalues should match", expectedEigenvalues.length, actualEigenvalues.length);

        for (int i = 0; i < expectedEigenvalues.length; i++) {
            assertEquals("Eigenvalue at index " + i + " should match",
                        expectedEigenvalues[i], actualEigenvalues[i], 1e-10);
        }
    }

    private double[][] createTridiagonalMatrix(double[] mainDiagonal, double[] secondaryDiagonal) {
        int n = mainDiagonal.length;
        double[][] matrix = new double[n][n];

        // Fill main diagonal
        for (int i = 0; i < n; i++) {
            matrix[i][i] = mainDiagonal[i];
        }

        // Fill secondary diagonals
        for (int i = 0; i < n - 1; i++) {
            matrix[i][i + 1] = secondaryDiagonal[i];  // upper diagonal
            matrix[i + 1][i] = secondaryDiagonal[i];  // lower diagonal
        }

        return matrix;
    }
}

